window.__QUIZ_DATA__=[{"id":"theory>Geography>2008>1>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract on a scale of 1 : 100,000 and answer this question      Draw an outline of the map on a scale of 1 : 300,000.  On your outline, show and name   (i) the settlement of Lariski and Wuna Dole  (ii) River Lakau and its direction of flow (use an arrow)  (iii) 1,100ft contour.","images":["data:image/png;base64,"],"marking_scheme":"Scale 1 : 300,000    Outline L = 12.2 \u00b1 2cm, B = 12.1cm \u00b1 2cm    (i) settlement of Lariski - (+ location + naming)  Settlement of Wura Dole - ( + location + naming)  Score wuna dole or (wuro dole)  (ii) River Lakau (+ location + naming, 1 Direction of flow).  (iii) 110ft contour.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2008>1>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"FINAL","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract on a scale of 1 : 100,000 and answer this question      Calculate the actual distance in kilometres along the railway line from the bridge near Zangoma to the bridg along River Gaji.","images":["data:image/png;base64,"],"marking_scheme":"Map measurement 25cm  Map scale : 1:100,000  Grounddistance=25 \u00d7 100,000100,000=25km  (24.8km - 25.2km)","marks":"5","difficulty":"2"},{"id":"theory>Geography>2008>1>c>i","subject":"Geography","year":"2008","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Study the map extract on a scale of 1 : 100,000 and answer this question      Using evidence from the map, state any three occupations of the people in the mapped area.","images":["data:image/png;base64,"],"marking_scheme":"- Teaching: presence of schools.  - Fishing: presence of many rivers.  - Trade and commerce: presence of market at Bara.  - Farming: presence of scattered cultivation.  - Grazing: presence of savanna and scrub.","marks":"3","difficulty":"2"},{"id":"theory>Geography>2008>1>c>ii","subject":"Geography","year":"2008","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Study the map extract on a scale of 1 : 100,000 and answer this question    Identify with reasons, the most important settlement on the map.","images":["data:image/png;base64,"],"marking_scheme":"Bara is the most important settlement in the area.  This is because it has a market and a school. It is also a Nodal settlement.","marks":"2","difficulty":"2"},{"id":"theory>Geography>2008>2>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"Describe the surveyor's chain.","images":[],"marking_scheme":"Surveyor's chain is 100ft long (Engineer's Chain) 66ft long-gunter chain.  - It is made of steel wires.  - A link is the distance from the middle of the central ring to the middle of the next central ring.  - Links are marked by brass tags.  - Connected by a set of oval links  - The chain has brass handles attached at each end.","marks":"12","difficulty":"1"},{"id":"theory>Geography>2008>2>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"Outline any three problems that could be encountered in the use of the surveyor's chain.","images":[],"marking_scheme":"Problems in the use of Surveyor's chain  - It is difficult to carry about.  - Chain survey cannot be used for enclosed, built up and bush covered areas.  - Chain sags during use.  - Bending of any of the steel wires leads to an inadequate measurement of result.  - Chain are slow and difficult by marshly or broken grounds","marks":"8","difficulty":"2"},{"id":"theory>Geography>2008>3>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Distinguish between local time and standard time.","images":[],"marking_scheme":"i. Standard time is associated with Greenwich mean time whereas local time is not.    ii. Standard time maintains the central time for time zone in which they are, whereas local time varies from place to place within a time zone.    iii. Local time varies from one longitude to another at the rate of 4 minutes per degree of longitude whereas standard time varies from one time zone to another on hourly basis of 15\u00b0 of longitude to 1 hour.    iv. Local time varies irregularly from longitude to longitude with each time zone whereas standard time falls within 24 time zones.","marks":"10","difficulty":"1"},{"id":"theory>Geography>2008>3>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"FINAL","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The local time of Town A, located on longitude 70\u00b0E and latitude 45\u00b0N, is 7.46p.m., calculate the longitude of Town B on the same latitude when its local time is 5.30a.m.","images":[],"marking_scheme":"Time in town A is 7:46 p.m  Time in town B is 5:30 a.m  Time difference is 19.46hours - 5:30 hour  Time difference is 14 hours 16 minutes  If 1 hours = 15\u00b0 / 1\u00b0 = 4 minutes.  Therefore 14 hours 16 minutes = 214\u00b0  If town A is on longitude 70\u00b0E  So town B's time is behind.  Therefore subtract 70\u00b0 from 214\u00b0  \u21d2 114\u00b0W","marks":"10","difficulty":"3"},{"id":"theory>Geography>2008>4>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"With the aid of diagrams, describe the appearance and mode of formation of this landforms.    Delta","images":["data:image/png;base64,"],"marking_scheme":"Appearance  - Bird's foot e.g Mississippi delta.  - Estuarine delta e.g vistula  - Fan-shaped  - Characterized by distributaries  - Arcuate delta e.g Niger delta.    Mode of formation  - It is formed by the deposition of loads carried from the upperport of the river.  - Its deposition takes places at the mouth of the river.  - River flows through the distributaries into the sea.  - A sheltered coast is formed when the distributaries extend into the sea.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2008>4>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"With the aid of diagrams, describe the appearance and mode of formation of this landforms.  block mountain","images":["data:image/png;base64,"],"marking_scheme":"Appearance  - It could be tilted.  - It is associated with rift valley.  - It has steep sides.  - It usually has flat topped.  - Examples : Vosges, black forest, Ruwemzori.    Formation  - As a result of lateral or vertical earth movements.  - Fault may be reversed, normal or thrust.  - Faulting may result from tensional/compressional forces.  - Tensional forces pull crystal blocks apart.  - Block apart  - Leaving the middle block to form block mountains.  - Compressional forces push the outside blocks up to form block mountains.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2008>4>c","subject":"Geography","year":"2008","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"With the aid of diagrams, describe the appearance and mode of formation of this landforms.  rock pedesta.","images":["data:image/png;base64,"],"marking_scheme":"Appearance: Mushroom - shaped  - Irregular surface  - Dome/flat-shaped  - Like a pillar in structure  - Consists of horizontal layers of hard and soft rocks.  - May range from 10 - 15 metres high.    Mode of Formation  - At right angles to the prevailing wind, alternate bands of soft and hard horizontal rocks lays.  - Alternate horizontal layers of hard and soft rocks are attacked by abrasive action.  - Serious undercutting occurs because abrasion is stronger at ground level.  - Soft rocks are eroded faster than the hard rocks.  - Irregular shaped feature called rock pedestal is produced.  - Found in desert e.g Sahara Desert.","marks":"5","difficulty":"3"},{"id":"theory>Geography>2008>5>a>i","subject":"Geography","year":"2008","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Differentiate between Erosion and Mass movement.","images":[],"marking_scheme":"- Erosion is the gradual wearing off of top soil while mass movement is the movement of loose rock materials down slope.  - Agents of erosion are running water, winds, waves and gracier while that of mass movement entails the force of gravity.  - Erosion involves scratching, polishing and plucking of loose rock surfaces while mass movement involves creeping, flowing, slumping, sliding and falling.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2008>5>a>ii","subject":"Geography","year":"2008","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Name two features each of river erosion and mass movement.","images":[],"marking_scheme":"The main features of river erosion are:  * Gorges, canyons, waterfalls, Rapids, Capture, Pot holes, Interlocking spurs.    The main features of Mass Movement are:  * Slumps and slide scars, slumped blocks, hummocky topography, Talus, Screes.","marks":"6","difficulty":"1"},{"id":"theory>Geography>2008>5>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Describe the factors that affect mass movement.","images":[],"marking_scheme":"- Volcanic eruption can also lead to mass movement.  - Present of lubricating moisture e.g presence of rain water, ice e.t.c which tends to promote mass movement down slope.  - Presence of vegetation tends to reduce the rate of movement down the slope and vice versa.  - The occurrence of earthquake often triggers off mass movement on steep slopes.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2008>6>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Differentiate between weather and climate.","images":[],"marking_scheme":"- Weather is the atmospheric condition of a place over a short period but climate is the average condition of a place over a long period of time.  - Weather changes more often but climate doesn't   - Weather describes the atmospheric condition of a small area, while climate describes the atmospheric condition of large area.","marks":"6","difficulty":"1"},{"id":"theory>Geography>2008>6>b>i","subject":"Geography","year":"2008","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Name the instruments used in measuring this weather element;    pressure.","images":[],"marking_scheme":"Pressure - Barometer.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2008>6>b>ii","subject":"Geography","year":"2008","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Name the instruments used in measuring this weather element;  Sunshine","images":[],"marking_scheme":"Sunshine - Sun-dial recorder, campbell strokes.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2008>6>b>iii","subject":"Geography","year":"2008","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Name the instruments used in measuring this weather element;  Rainfall.","images":[],"marking_scheme":"Rainfall - Raingauge.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2008>6>b>iv","subject":"Geography","year":"2008","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Name the instruments used in measuring this weather element;  wind speed","images":[],"marking_scheme":"Wind speed - Anemometer.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2008>6>c","subject":"Geography","year":"2008","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Explain how wind speed is measured and recorded.","images":[],"marking_scheme":"How wind speed is measured  - The speed of the wind in kilometre per hour.  - Wind speed is measured with anemometer.  - It is placed in an open space.  - Anemometer consists of four metal cups fixed to a metal arm.  - The shaft is connected to a meter.  - The number of rotation is indicated to give the wind speed in km/hr.    How wind speed is recorded  - The record is signed by the observer.  - Reading is taken twice daily e.g 9.00 hours and 15.00 hours.  - Stating the data of recording and recording in a note book.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2008>7>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Describe the three stages of development of a river along its course.","images":[],"marking_scheme":"The stages of development of a river are:  - Upper course/Torrent stage/Youthful stage  - Middle course/Valley course/Maturity stage  - Low course/Plain course/Old stage.    Upper Course  - This stage of the river occurs near the source or mountain area.  - The river flows swiftly as it descends the slopes of the mountain.  - The river in vertical corrosion is very active.  - The main features include river capture, narrow steep-sided (V-shaped), Valleys, rapids and waterfalls, pot holes, interlocking spurs, gorges, plunge pool e.t.c.    Middle course  - Presence of a gentle gradient.  - It widens its valley whereby lateral erosion becomes dominant.  - The velocity is reduced due to the reduction of gradient.  - Deposition begins to take place at valley sides and floor.  - The main features produced are meanders, v-shaped valleys, terrace, increase in volume of water, bluffs river cliff e.t.c.    Low course  - This stage is the last towards the mouth.  - The flow is sluggish.  - The gradient at this stage is very gentle.  - Deposition of loads is the major function.  - The main features produced as wide floodplain, delta, ox-bow lakes, braided stream, leaves e.t.c.","marks":"12","difficulty":"3"},{"id":"theory>Geography>2008>7>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Highlight two ways in which rivers are important to man.","images":[],"marking_scheme":"- Source of fish  - For recreational activities   - A medium of transportation  - Generation of Hydro-electric power (H. E. P)  - Source of water for irrigation.  - Water for domestic and industrial use.  - Source of minerals e.g alluvial gold, diamond e.t.c","marks":"8","difficulty":"1"},{"id":"theory>Geography>2008>8>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Describe the Warm Temperate, Western Margin climate (Mediterranean type) under this heading:    location","images":[],"marking_scheme":"- It is found between latitudes 30\u00b0 and 45\u00b0 north and south of the equator.  - It is confirmed to the western portion of the continential masses.  - North Africa (Tunisia, Morocco, Libya), Central Chile, South West of South Africa, Southern California, Mediterranean Europe (France, Spain, Italy) and southern Western Austrialia.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2008>8>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Describe the Warm Temperate, Western Margin climate (Mediterranean type) under this heading:  climatic characteristics","images":[],"marking_scheme":"- A dry warm summer of temperature between 21\u00b0C to 27\u00b0C  - Mean rainfall of 600 - 900mm  - It has abundance of rainfall in winter  - Bright sunny weather with hot, dry summer and wet mild winter.  Four seasons winter temperature never below 0\u00b0c(5\u00b0c - 6\u00b0c).","marks":"5","difficulty":"2"},{"id":"theory>Geography>2008>8>c","subject":"Geography","year":"2008","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Describe the Warm Temperate, Western Margin climate (Mediterranean type) under this heading:  vegetation.","images":[],"marking_scheme":"- The dominant vegetation is evergreen woodland such as oak, eucalyptus plants.  - Presence of grasses  - There is prominantly evergreen coniferous forest such as pines, firs and cedars.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2008>8>d","subject":"Geography","year":"2008","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Describe the Warm Temperate, Western Margin climate (Mediterranean type) under this heading:  Human activities.","images":[],"marking_scheme":"- Fruit canning   - Wine production  - Viticulture - people growing grape fruits  - Transhumance - livestock farming  - Crop production such as wheat nd rice using irrigation.","marks":"5","difficulty":"3"},{"id":"theory>Geography>2008>9>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Name two light industries and two heavy industries.","images":[],"marking_scheme":"Light industries:  - Pharmaceutical  - Textile   - Leather  - Office consumables   - Food processing   - Printing   - Paper      Heavy Industries  - Ship building  - Cement manufacturing  - Motor assembly plants  - Aircraft  - Aluminium  - Machine tools","marks":"6","difficulty":"1"},{"id":"theory>Geography>2008>9>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline four factors which an industrialist must consider before locating an industry in a particular place.","images":[],"marking_scheme":"- Large market  - Proximity to source of raw materials  - Proximity to labour  - Adequate capital  - Government policy  - Power supply  - Adequate transport network","marks":"8","difficulty":"2"},{"id":"theory>Geography>2008>9>c","subject":"Geography","year":"2008","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Highlight four contributions of manufacturing industries to the economy of any country.","images":[],"marking_scheme":"- Development of infrastructures  - Source of income to industrialist  - Employment opportunities  - Improvemnt in standard of living  - Transfer of technology  - Increase in Gross National Product (GNP)  - Conservation of foreign exchange  - It promotes international trade","marks":"6","difficulty":"2"},{"id":"theory>Geography>2008>10>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"In what four ways does a town differ from a village?","images":[],"marking_scheme":"- A town offers opportunities for secondary and tertiary activities, while villages offer opportunities for primary activities mainly.    - A town occupies a large scale than a village.    - A town has more population compare to a village.    - A town is a heterogenous community, while a village is a homogenous community.     - A town has more or many social amenities but fewer in villages.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2008>10>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"With examples, describe four functions which a village may perform for a town.","images":[],"marking_scheme":"- Market for industrial goods manufactured in towns e.g Ihie to Aba.  - Food supply, particularly vegetables e.g Ogwago to Enugu.  - Labour supply, particularly unskilled labour e.g Okpanam and Umutu supply unskilled labour for Asaba in Delta state.  - Provision of raw materials to industries in towns e.g Ngwa oil palm to vegetable oil industries in Aba.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2008>11>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"State four advantages of rural-urban migration.","images":[],"marking_scheme":"- It challenges the government to develop rural area.  - It helps urban growth  - Enhancement of commercial activities  - It creates labour for factories and industries  - It create opportunity to develop standard of living.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2008>11>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Describe four effects of rural-urban migration on the urban areas.","images":[],"marking_scheme":"- Increase in government expenditure.  - Increase in crime rate  - Housing problem  - Unemployment/under employment in urban areas.   - High cost of living  - Traffic congestions.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2008>11>c","subject":"Geography","year":"2008","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Highlight two measures that can be taken to stop rural-urban migration.","images":[],"marking_scheme":"- Development of good transport network.  - Development of rural areas.  - Soft loans to rural farmers.  - Provision of social amenities in rural areas.  - Provision of job opportunities in rural areas.","marks":"4","difficulty":"1"},{"id":"theory>Geography>2008>12>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TOURISM","question":"Outline any five factors that contribute to the development of tourism in Nigeria.","images":[],"marking_scheme":"They include, wild life, effective publicity, improvement in security, need to earn foreign exchange, hotels of international standards, fine beaches, favourable climate, presence of historic sites.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2008>12>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TOURISM","question":"Highlight any five contributions of the tourist industry to the economic development in Nigeria.","images":[],"marking_scheme":"- Encouragement of local craft industries.  - Income to government and individuals.  - Conservation of wild life.  - Job opportunities.   - Improved commercial activities.  - Foreign exchange earning.  - Improved standard of living.  - Improved transport system.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2008>13>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"In what four ways has the physical setting of the Sokoto plains of Nigeria influenced the types of economic activities in the region?","images":[],"marking_scheme":"- Presence of rivers encourages fishing and tourism.  - Presence of mineral deposits encourages mining activities.  - Presence of abundant pasture supports animal rearing.  - Presence of vast rolling plants encourages animal rearing in the region.  - Long period of dry season necessitates the practice of irrigation agriculture.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2008>13>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Highlight any four problems of development facing this region.","images":[],"marking_scheme":"- Low literacy rate of the population.  - Inadequate rainfall  - The cost of providing infrastructure and amenities is high.  - Sparsity of population makes it difficult for the region to attract major development projects.  - Occasional flooding  - Threat of desert encroachment","marks":"8","difficulty":"3"},{"id":"theory>Geography>2008>13>c","subject":"Geography","year":"2008","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Outline two ways in which any of the problems in (b) above could be solved.","images":[],"marking_scheme":"- Aerial spray to kill pest   - Improvement of transport network.  - Afforestation  - Irrigation  - Provision of medicare  - Improvement in technology","marks":"4","difficulty":"1"},{"id":"theory>Geography>2008>14>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Draw an outline map of Nigeria.  On the map, show and name:  (i) the railway line from Lagos to Minna  (ii) one area each of limestone, coal, columbite, gold","images":["data:image/png;base64,"],"marking_scheme":"(i) Railway line from Lagos to Minna   (ii) 4 areas at    Limestone: Ewekoro, Sokoto, Nkalagu, Ukpitla, Gboko e.t.c.  Gold: Ilesha, Sokoto, Minna e.t.c  Columbite: Barkin Ladi, Jos, Bukuru e.t.c.  Coal: Enugu, Okaba e.t.c","marks":"10","difficulty":"3"},{"id":"theory>Geography>2008>14>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Describe the method of mining columbite in Nigeria.","images":[],"marking_scheme":"* Open cast, removal of overburden, application of dynamites and explosives, usage of mechanical shovels, pick axes, dragline collects into heaps, usage of monitor to wash one, usage of trucks to convey ore to factory for smelting, conveyance by rail for export.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2008>14>c","subject":"Geography","year":"2008","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Highlight three adverse effects of mining in one of the mining areas in question (a) (ii).","images":[],"marking_scheme":"- Mining hazards e.g collapse of mines  - Environmental pollution  - Environmental degradation  - Loss of farm lands/grazing lands.  - Health hazards i.e asthma, lung and heart disorders.  - Communal conflicts","marks":"4","difficulty":"2"},{"id":"theory>Geography>2008>15>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw an outline map of Africa.  On the map, mark and name the following:  (i) the Tropical Climatic region  (ii) the Hot Desert Climatic region;  (iii) the Warm Temperate Eastern Marging Climatic region.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2008>15>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Describe any three characteristics of the Tropical Climate.","images":[],"marking_scheme":"- Rainfall is mainly convectional   - Average rainfall is 75cm.  - Distinct wet and dry season.  - Rainfall decreases from the equatorial borders to the desert borders.  - Temperature is high between 21\u00b0C and 32\u00b0C.  - Prevailing winds - Tropical maritime and Tropical continental (S. W. Trade winds and N. E Tradewinds)","marks":"6","difficulty":"2"},{"id":"theory>Geography>2008>15>c","subject":"Geography","year":"2008","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Outline three ways in which the vegetation of Tropical Climate has adapted to the climatic conditions of the region.","images":[],"marking_scheme":"- Trees shed their leaves in the dry season to reduce transpiration.  - Plants have developed bulbous stems to store water in the dry season.  - Some have long tap roots which can reach underground water.  - Vegetation is seasonal in nature - green in the rainy season, and brown in the dry season.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2008>16>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Highlight three factors which favour lumbering in either Zaire or Cote d'Ivoire.","images":[],"marking_scheme":"- Availability of labour.  - High demand for hardwood in foreign countries  - High rainfall all year round  - High temperature all year round  - The presence of dense Tropical desert.  - Presence of many economic trees such as obeche, iroko, mahogamy, ebony e.t.c.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2008>16>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Describe the method of lumbering in one of the countries chosen in question (a).","images":[],"marking_scheme":"- Truks carry logs to sawmills or ports of export.  - Logs are dragged by tractors to loading ports.  - The tree is then cut down with either axe or chain saws.  - Platforms of about 2 - 3 metres high are built around the trees with buttress roots.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2008>16>c","subject":"Geography","year":"2008","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Outline four problems associated with lumbering in Africa.","images":[],"marking_scheme":"- It leads to the depletion of natural forest resources.  - Insufficient capital  - Difficult terrain  - It leads to the disappearance of wild life.  - Exploitation of timber exposes the area to agents of erosion.  - Forest in some parts are far from the coast thus increasing costs of transportation.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2008>17>a","subject":"Geography","year":"2008","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw an outline map of Africa.  On the map, show and name:  (i) one major river that drains into the Mediterranean sea  (ii) one major river that crosses the Equator twice  (iii) one major river that drains into the Indian ocean;  (iv) one rift valley lake  (v) One man-made lake  (vi) One lake crossed by the Equator","images":["data:image/png;base64,"],"marking_scheme":"Outline: Rivers and Lake  (i) The Nile  (ii) River congo/zaire  (iii) River Zambezi, River Limpopo  (iv) Lake Malawi, Lake Tanganyinka, Lake Kivu, Lake Edward.  (v) Lake volta, Lake Kanji, Lake Kariba e.t.c  (vi) Lake victoria","marks":"10","difficulty":"3"},{"id":"theory>Geography>2008>17>b","subject":"Geography","year":"2008","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Highlight any five factors that limit the use of African rivers.","images":[],"marking_scheme":"- High load in suspension/debris.  - Presence of water weeds/water hycinths.  - Presence of cataracts, rapids and water falls.  - Some have shallow river beds.  - Scarce capital for port development.  - Fluctuation in river volume.  - Silting of river mouths.","marks":"10","difficulty":"2"}];